-- ============================================================================
-- Quiz Seed: Leviticus — Part 1 (Chapters 1–10)
-- 3 difficulties × 10 chapters = 160 total questions
--   kids:   3 per chapter  = 30
--   teens:  5 per chapter  = 50
--   adults: 8 per chapter  = 80
-- ============================================================================

-- ═══ Leviticus Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 1, 'kids', 1, 'Where did God speak to Moses at the start of Leviticus?', 'Out of the tabernacle of the congregation', 'From the burning bush', 'From a cloud on Mount Sinai', 'From the river bank', 'a', 'Leviticus 1:1 — "And the LORD called unto Moses, and spake unto him out of the tabernacle of the congregation."'),
('Leviticus', 1, 'kids', 2, 'What kind of animal could be used for a burnt offering from the herd?', 'A male without blemish', 'A female with spots', 'Any animal the person chose', 'Only a white animal', 'a', 'Leviticus 1:3 — "If his offering be a burnt sacrifice of the herd, let him offer a male without blemish: he shall offer it of his own voluntary will at the door of the tabernacle of the congregation before the LORD."'),
('Leviticus', 1, 'kids', 3, 'What did the priests do with the blood of the burnt offering?', 'Sprinkle it round about upon the altar', 'Pour it on the ground outside the camp', 'Give it to the offerer to take home', 'Bury it in the ground', 'a', 'Leviticus 1:5 — "And he shall kill the bullock before the LORD: and the priests, Aaron''s sons, shall bring the blood, and sprinkle the blood round about upon the altar that is by the door of the tabernacle of the congregation."'),
-- Teens
('Leviticus', 1, 'teens', 1, 'What did the offerer do with his hand before the animal was slaughtered?', 'He put his hand upon the head of the burnt offering so it would be accepted to make atonement', 'He washed his hands in the basin', 'He raised both hands toward heaven', 'He touched the altar with his hand', 'a', 'Leviticus 1:4 — "And he shall put his hand upon the head of the burnt offering; and it shall be accepted for him to make atonement for him."'),
('Leviticus', 1, 'teens', 2, 'What three types of animals are described as options for the burnt offering in chapter 1?', 'An animal from the herd (bullock), an animal from the flock (sheep or goat), and a fowl (turtledove or pigeon)', 'Only oxen and doves', 'Only sheep and goats', 'Cattle, camels, and donkeys', 'a', 'Leviticus 1:2-14 — The chapter provides three categories: cattle (vv.3-9), flock animals (vv.10-13), and birds (vv.14-17), accommodating varying levels of wealth among the worshippers.'),
('Leviticus', 1, 'teens', 3, 'How was a bird offered differently from a larger animal in the burnt offering?', 'The priest wrung off the bird''s head and tore it by its wings without dividing it asunder, and burned it on the altar', 'The bird was burned whole without any preparation', 'The bird was released alive', 'The bird''s blood was sprinkled on the people', 'a', 'Leviticus 1:15-17 — "And the priest shall bring it unto the altar, and wring off his head, and burn it on the altar; and the blood thereof shall be wrung out at the side of the altar."'),
('Leviticus', 1, 'teens', 4, 'What did the priests burn along with the pieces of the burnt offering?', 'The head, the fat, the inwards, and the legs after they were washed with water', 'Only the meat and bones', 'Only the fat parts', 'The skin and the feathers', 'a', 'Leviticus 1:8-9 — "And the priests, Aaron''s sons, shall lay the parts, the head, and the fat, in order upon the wood that is on the fire which is upon the altar: But his inwards and his legs shall he wash in water: and the priest shall burn all on the altar."'),
('Leviticus', 1, 'teens', 5, 'What phrase describes the result of the burnt offering that pleased the LORD?', 'A sweet savour unto the LORD', 'An acceptable payment to the priest', 'A holy ransom for the people', 'A worthy tribute to the tabernacle', 'a', 'Leviticus 1:9 — "But his inwards and his legs shall he wash in water: and the priest shall burn all on the altar, to be a burnt sacrifice, an offering made by fire, of a sweet savour unto the LORD."'),
-- Adults
('Leviticus', 1, 'adults', 1, 'What is the Hebrew word for burnt offering and what does it mean theologically?', 'Olah — from the verb alah meaning "to go up," signifying that the entire sacrifice ascends to God in smoke, representing complete dedication with no portion kept back', 'Korban — meaning "a gift brought near"', 'Zebach — meaning "that which is slaughtered"', 'Minchah — meaning "a tribute offering"', 'a', 'Leviticus 1:3 — The olah (עֹלָה) is the whole burnt offering. Unlike peace offerings where the offerer shared in the meal, the entire olah was consumed on the altar, symbolising total consecration of the worshipper to God.'),
('Leviticus', 1, 'adults', 2, 'What is the typological significance of the burnt offering pointing to Christ?', 'It typifies Christ''s complete self-offering on the cross — a perfect, unblemished sacrifice wholly devoted to God as an atoning substitute, fulfilling what every animal offering could only foreshadow', 'It has no connection to the New Testament', 'It only pointed to Moses as mediator', 'It symbolised the giving of the law', 'a', 'Leviticus 1:3 — "A male without blemish" prefigures 1 Peter 1:19 — "a lamb without blemish and without spot." The laying on of hands (v.4) portrays substitutionary atonement, fully realised in Christ (Hebrews 10:10).'),
('Leviticus', 1, 'adults', 3, 'What is the significance of the phrase "of his own voluntary will" in verse 3?', 'It emphasises that worship under the Levitical system was to be voluntary, not coerced — anticipating the new covenant principle of willing, heart-motivated offering rather than mere external compliance', 'It means the animal chose to come', 'It means only rich people could offer', 'It was a legal requirement with no spiritual meaning', 'a', 'Leviticus 1:3 — "He shall offer it of his own voluntary will." The Hebrew lirretsono ("for his acceptance") shows worship must be free and heartfelt. Paul echoes this in 2 Corinthians 9:7 — "God loveth a cheerful giver."'),
('Leviticus', 1, 'adults', 4, 'Why were the inwards and legs washed before burning, and what does this teach?', 'The washing removed impurities from the parts associated with digestion and locomotion, symbolising that what is offered to God must be cleansed — pointing to Christ''s perfect moral purity throughout His life and death', 'It was a hygienic requirement only', 'The washing made the meat taste better', 'It was done to please the priests', 'a', 'Leviticus 1:9 — "His inwards and his legs shall he wash in water." The inwards (seat of appetite) and legs (walk/conduct) being washed speaks to inner purity, fulfilled in Christ who had no sin in thought or deed (Hebrews 4:15).'),
('Leviticus', 1, 'adults', 5, 'How does the tiered animal system (bull, sheep/goat, turtledove) reflect God''s character?', 'It demonstrates God''s gracious accommodation to different economic circumstances — the poor could offer birds — showing that access to atonement was not reserved for the wealthy, foreshadowing the gospel''s universal access', 'It shows only the rich could have their sins forgiven', 'It ranked the value of worshippers', 'It was purely a practical arrangement', 'a', 'Leviticus 1:3,10,14 — Three tiers of offering ensure that "whosoever will" can bring a sacrifice. Mary offered two turtledoves at Jesus'' presentation (Luke 2:24) — the poorest option — yet the Messiah Himself lay in her arms.'),
('Leviticus', 1, 'adults', 6, 'What is the significance of the altar fire being described as consuming the sacrifice?', 'Fire represents divine holiness consuming what is presented to God — the same divine fire that later fell from heaven to accept or reject offerings (Leviticus 9:24), demonstrating that true atonement requires divine action, not merely human ritual', 'The altar fire was ordinary cooking fire', 'Fire was used only for practical burning', 'The fire represented human zeal', 'a', 'Leviticus 9:24 — "And there came a fire out from before the LORD, and consumed upon the altar the burnt offering." This holy fire was to be kept perpetually burning (Leviticus 6:13), representing God''s unceasing acceptance of consecrated worship.'),
('Leviticus', 1, 'adults', 7, 'How does the structure of Leviticus 1 fit within the broader literary structure of the Pentateuch?', 'Leviticus opens immediately after Exodus closes with God''s glory filling the tabernacle — the sacrificial laws are God''s answer to how sinful Israel may approach and remain in the presence of the holy God who now dwells among them', 'Leviticus contradicts the Exodus narrative', 'Leviticus was written much later and added independently', 'The chapter has no connection to Exodus', 'a', 'Exodus 40:34-35 records the glory filling the tabernacle; Leviticus 1:1 opens with God speaking from within it. The whole sacrificial system answers the question: How can holy God dwell with sinful people? (cf. Hebrews 9:1-10)'),
('Leviticus', 1, 'adults', 8, 'What does the phrase "at the door of the tabernacle" reveal about the theology of access?', 'The offering must be made at the divinely appointed place — the threshold between God''s dwelling and the worshipper''s world — showing that access to God is only through His ordained way, prefiguring Christ as "the door" (John 10:9)', 'It was a logistical instruction only', 'Any location in the camp was acceptable', 'The door symbolised the way out of trouble', 'a', 'Leviticus 1:3 — "At the door of the tabernacle of the congregation before the LORD." The Hebrew petach ohel moed ("door of the tent of meeting") is the ordained point of access to God, foreshadowing John 10:9 — "I am the door: by me if any man enter in, he shall be saved."');

-- ═══ Leviticus Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 2, 'kids', 1, 'What was the meat offering (grain offering) made of?', 'Fine flour with oil poured on it and frankincense', 'Roasted meat and vegetables', 'Bread and grapes', 'Dried fish and salt', 'a', 'Leviticus 2:1 — "And when any will offer a meat offering unto the LORD, his offering shall be of fine flour; and he shall pour oil upon it, and put frankincense thereon."'),
('Leviticus', 2, 'kids', 2, 'What two things were NOT allowed in the grain offering?', 'Leaven and honey — neither was to be burned as an offering to God', 'Salt and oil', 'Frankincense and fine flour', 'Water and milk', 'a', 'Leviticus 2:11 — "No meat offering, which ye shall offer unto the LORD, shall be made with leaven: for ye shall burn no leaven, nor any honey, in any offering of the LORD made by fire."'),
('Leviticus', 2, 'kids', 3, 'What seasoning was always to be included in every offering?', 'Salt', 'Pepper', 'Cumin', 'Cinnamon', 'a', 'Leviticus 2:13 — "And every oblation of thy meat offering shalt thou season with salt; neither shalt thou suffer the salt of the covenant of thy God to be lacking from thy meat offering: with all thine offerings thou shalt offer salt."'),
-- Teens
('Leviticus', 2, 'teens', 1, 'What portion of the grain offering did the priest burn on the altar, and what happened to the rest?', 'A memorial portion (the handful) was burned; the remainder belonged to Aaron and his sons as most holy from the offerings of the LORD made by fire', 'The entire offering was burned completely', 'The remainder was given back to the offerer', 'The rest was distributed to the poor', 'a', 'Leviticus 2:2-3 — "And the priest shall burn the memorial of it upon the altar... And the remnant of the meat offering shall be Aaron''s and his sons'': it is a thing most holy of the offerings of the LORD made by fire."'),
('Leviticus', 2, 'teens', 2, 'What three forms could the baked grain offering take?', 'Baked in an oven, baked in a pan, or fried in a frying pan', 'Only baked in an oven', 'Only made as flat unleavened cakes', 'Only as fine flour poured out', 'a', 'Leviticus 2:4-7 — Three cooking methods are described: baked in an oven (v.4), baked in a pan (v.5), or fried in a frying pan (v.7), each brought to the priest as an offering to the LORD.'),
('Leviticus', 2, 'teens', 3, 'What was the grain offering of firstfruits made from?', 'Green ears of corn dried by the fire, or beaten corn (crushed grain), with oil and frankincense', 'Ripe stored wheat only', 'Barley ground into fine powder', 'Fruit from the first harvest of figs', 'a', 'Leviticus 2:14-15 — "And if thou offer a meat offering of thy firstfruits unto the LORD, thou shalt offer for the meat offering of thy firstfruits green ears of corn dried by the fire, even corn beaten out of full ears. And thou shalt put oil upon it, and lay frankincense thereon."'),
('Leviticus', 2, 'teens', 4, 'Why was leaven (yeast) forbidden from offerings burned on the altar to God?', 'Leaven symbolised corruption and sin — nothing impure could be offered as a fire-offering to God', 'Leaven made the offering too large', 'Leaven was too expensive for the poor', 'Leaven was used only in peace offerings', 'a', 'Leviticus 2:11 — "No meat offering, which ye shall offer unto the LORD, shall be made with leaven: for ye shall burn no leaven, nor any honey, in any offering of the LORD made by fire." Leaven consistently represents sin or corruption in Scripture (1 Corinthians 5:7-8).'),
('Leviticus', 2, 'teens', 5, 'What does God call the salt used in offerings "the salt of"?', 'The covenant of thy God', 'The blessing of the LORD', 'The sanctification of Israel', 'The purification of the altar', 'a', 'Leviticus 2:13 — "Neither shalt thou suffer the salt of the covenant of thy God to be lacking from thy meat offering: with all thine offerings thou shalt offer salt." Salt preserves and purifies, making it a fitting symbol of God''s enduring covenant.'),
-- Adults
('Leviticus', 2, 'adults', 1, 'What is the Hebrew term for the grain offering and what is its root meaning?', 'Minchah — meaning "a tribute" or "gift presented to a superior," indicating the offering expressed homage and dependence, not atonement for sin', 'Olah — meaning "that which goes up"', 'Chattath — meaning "sin"', 'Shelamim — meaning "peace"', 'a', 'Leviticus 2:1 — The minchah (מִנְחָה) is a non-blood offering, signifying the worshipper''s dedication of labour and provision to God. Before Moses, the term was used of gifts brought to superiors (Genesis 32:13), underlining submission and gratitude.'),
('Leviticus', 2, 'adults', 2, 'What is the typological significance of the grain offering in relation to Christ?', 'The fine flour (perfect uniformity), oil (the Spirit), frankincense (fragrant intercession), salt (incorruption), and absence of leaven (sinlessness) together portray the perfect humanity of Christ — wholly given to God', 'It only represented Israel''s agricultural economy', 'It had no prophetic meaning', 'It symbolised only the priesthood', 'a', 'Leviticus 2:1-2 — Fine flour speaks of Christ''s perfectly balanced character (Hebrews 7:26); oil of the Holy Spirit (Isaiah 61:1); frankincense of His intercession (Hebrews 7:25); salt of His incorruptibility; no leaven of His sinlessness (1 Peter 2:22).'),
('Leviticus', 2, 'adults', 3, 'What does the prohibition of honey alongside leaven reveal about the offering''s theology?', 'Honey, though pleasant, represents natural sweetness or human sentiment that ferments — offerings to God must not be enhanced by what merely pleases the human senses but must be according to His prescription', 'Honey was forbidden because it was rare', 'Honey and leaven were identical in meaning', 'Honey was reserved for the high priest only', 'a', 'Leviticus 2:11 — "Neither shall ye burn any honey as an offering to the LORD made by fire." Unlike leaven, honey does not corrupt bread but can ferment. The prohibition guards against offerings shaped by human taste rather than divine command.'),
('Leviticus', 2, 'adults', 4, 'What is the theological significance of the "salt of the covenant" requirement?', 'Salt preserves from decay and was used in Near Eastern treaty-making to seal binding agreements — requiring salt in every offering affirmed that each act of worship renewed and reaffirmed the covenant between God and Israel', 'Salt was a rare preservative with no symbolic meaning', 'The salt requirement was purely hygienic', 'Salt represented the priest''s authority', 'a', 'Leviticus 2:13 — "The salt of the covenant of thy God." Numbers 18:19 calls the priestly portions "a covenant of salt for ever." 2 Chronicles 13:5 — God gave David''s kingdom "by a covenant of salt," signifying permanence and incorruptibility.'),
('Leviticus', 2, 'adults', 5, 'How does the grain offering complement the burnt offering in Israel''s worship system?', 'The burnt offering (blood sacrifice for atonement) addressed the problem of sin, while the grain offering (labour of hand) expressed consecration of daily life and work — together they represent the whole person offered to God', 'The grain offering replaced the burnt offering for wealthy Israelites', 'The two offerings were identical in purpose', 'The grain offering was for Gentiles only', 'a', 'Numbers 15:1-12 establishes that grain and drink offerings accompanied burnt offerings, creating a composite act of worship. Atonement (burnt) + consecration of labour (grain) + joy/fellowship (peace) together capture full covenantal response to God.'),
('Leviticus', 2, 'adults', 6, 'What New Testament passage cites the firstfruits concept connected to the grain offering?', '1 Corinthians 15:20 — "But now is Christ risen from the dead, and become the firstfruits of them that slept" — connecting the firstfruits offering to the resurrection of Christ as the first and guarantee of the general resurrection', 'Romans 3:25 only', 'Hebrews 10:1 only', 'Revelation 1:8 only', 'a', 'Leviticus 2:14 — The firstfruits offering anticipates 1 Corinthians 15:20,23 and James 1:18. Christ''s resurrection as firstfruits of the harvest of the dead gives the ancient offering its fullest theological meaning.'),
('Leviticus', 2, 'adults', 7, 'What is the significance of oil being poured upon the grain offering?', 'Oil in Scripture consistently represents the Holy Spirit — the anointing presence of God; the grain offering''s oil thus signifies that consecrated human labour is only acceptable to God when empowered and sanctified by the Spirit', 'Oil was a preservative only', 'Oil symbolised wealth of the offerer', 'Oil replaced the blood in grain offerings', 'a', 'Leviticus 2:1 — "He shall pour oil upon it." Oil is the consistent symbol of the Holy Spirit from the anointing of priests (Leviticus 8:12) to Zechariah 4:6 ("Not by might, nor by power, but by my spirit") and the seven lamps of Revelation 4:5.'),
('Leviticus', 2, 'adults', 8, 'What does the priests'' eating of the remainder as "most holy" teach about God''s provision?', 'God ordained that those who minister at the altar live from the altar — the priests'' portion came directly from what was brought to God, teaching that God''s servants are sustained by His provision through the worship of His people', 'The priests received the remainder as wages for physical labour', 'The remainder was a secondary inferior portion', 'The priests had to purchase their food separately', 'a', 'Leviticus 2:3,10 — "The remnant... shall be Aaron''s and his sons'': it is a thing most holy." Paul applies this principle in 1 Corinthians 9:13-14 — "They which minister about holy things live of the things of the temple."');

-- ═══ Leviticus Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 3, 'kids', 1, 'What was the peace offering used to express?', 'Fellowship and thankfulness between the worshipper and God', 'Punishment for doing wrong', 'A payment to the priests', 'A gift for the king', 'a', 'Leviticus 3:1 — "And if his oblation be a sacrifice of peace offering, if he offer it of the herd; whether it be a male or female, he shall offer it without blemish before the LORD." The peace offering celebrated fellowship and gratitude.'),
('Leviticus', 3, 'kids', 2, 'Which parts of the animal were specifically given to the LORD from the peace offering?', 'All the fat', 'Only the bones', 'The ears and tail', 'The hooves only', 'a', 'Leviticus 3:16 — "And the priest shall burn them upon the altar: it is the food of the offering made by fire for a sweet savour: all the fat is the LORD''S."'),
('Leviticus', 3, 'kids', 3, 'What two things were the Israelites told they must never eat?', 'Fat and blood', 'Salt and oil', 'Meat and bread', 'Honey and leaven', 'a', 'Leviticus 3:17 — "It shall be a perpetual statute for your generations throughout all your dwellings, that ye eat neither fat nor blood."'),
-- Teens
('Leviticus', 3, 'teens', 1, 'What three types of animals could be offered as a peace offering?', 'An animal from the herd (ox), a lamb from the flock, or a goat', 'Only oxen and goats', 'Only young animals', 'Only male animals', 'a', 'Leviticus 3:1,6,12 — The chapter covers three sections: offering from the herd (vv.1-5), offering of a lamb (vv.6-11), and offering of a goat (vv.12-16), unlike the burnt offering which excluded female animals.'),
('Leviticus', 3, 'teens', 2, 'What did the offerer do with his hand before slaughtering the peace offering?', 'He laid his hand upon the head of the offering and killed it at the door of the tabernacle', 'He raised his hand in prayer first', 'He touched the priest''s garment', 'He washed his hands in the basin', 'a', 'Leviticus 3:2 — "And he shall lay his hand upon the head of his offering, and kill it at the door of the tabernacle of the congregation: and Aaron''s sons the priests shall sprinkle the blood upon the altar round about."'),
('Leviticus', 3, 'teens', 3, 'Which specific fat parts of the animal were to be burned on the altar in the peace offering?', 'The fat that covered the inwards, both kidneys with the fat upon them, and the caul (the lobe above the liver)', 'Only the external fat layer', 'The fat from the tail and ears only', 'All internal organs without distinction', 'a', 'Leviticus 3:3-4 — "And he shall offer of the sacrifice of the peace offering an offering made by fire unto the LORD; the fat that covereth the inwards, and all the fat that is upon the inwards, And the two kidneys, and the fat that is on them."'),
('Leviticus', 3, 'teens', 4, 'What made the lamb''s peace offering different from the goat''s?', 'The lamb''s entire fat tail (the rump) was also offered to the LORD, which was not specified for the goat offering', 'The lamb offering required more priests', 'The lamb was offered at a different time of day', 'The lamb''s blood was not sprinkled on the altar', 'a', 'Leviticus 3:9 — "And he shall offer of the sacrifice of the peace offering an offering made by fire unto the LORD; the fat thereof, and the whole rump, it shall he take off hard by the backbone; and the fat that covereth the inwards."'),
('Leviticus', 3, 'teens', 5, 'Why was the fat described as "the LORD''s" in the peace offering?', 'Because the fat was the choicest, richest portion — reserved for God as an acknowledgment that the best belongs to Him and nothing less is worthy of divine acceptance', 'Because the priests were forbidden from eating it', 'Because the fat made the offering burn faster', 'Because fat was considered unclean for human consumption', 'a', 'Leviticus 3:16 — "And the priest shall burn them upon the altar: it is the food of the offering made by fire for a sweet savour: all the fat is the LORD''S." This reinforces that God receives the premier portion of what is offered.'),
-- Adults
('Leviticus', 3, 'adults', 1, 'What is the Hebrew term for the peace offering and its root meaning?', 'Shelamim — from shalom, meaning completeness, wholeness, and well-being, indicating the offering celebrated a state of restored or confirmed relationship between the worshipper and God', 'Olah — meaning ascent to God', 'Asham — meaning guilt', 'Chattath — meaning sin and purification', 'a', 'Leviticus 3:1 — The shelamim (שְׁלָמִים) is from the root shalam, the same root as shalom. Unlike the burnt offering (complete surrender) and sin offering (atonement), the shelamim celebrated existing peace with God and was shared between God, priest, and offerer.'),
('Leviticus', 3, 'adults', 2, 'How was the peace offering distinct in that it was shared among three parties?', 'The fat and kidneys were burned for God, the breast and right shoulder went to the priests (heave and wave portions), and the remainder was eaten by the offerer and family — portraying communion at God''s table', 'The entire offering was consumed by fire', 'The priest received all except the blood', 'The offerer had no portion in the meal', 'a', 'Leviticus 7:28-34 describes the full peace offering distribution: fat for God (3:3-5), breast as wave offering for Aaron and sons (7:30-31), right shoulder for the officiating priest (7:32-33), and the remainder for the offerer (7:15-18). This tri-partite meal pictures divine fellowship.'),
('Leviticus', 3, 'adults', 3, 'What typological connection does the peace offering have to Christ and the Lord''s Supper?', 'Christ is our peace (Ephesians 2:14) and the Lord''s Supper echoes the communal meal of the peace offering — believers eat at the table of the One whose sacrifice secured their shalom with God', 'There is no connection to the New Testament', 'It only typified the Mosaic covenant', 'It pointed forward only to Jewish temple worship', 'a', 'Leviticus 3:1 — Ephesians 2:14 — "He is our peace (shalom)." Colossians 1:20 — "Having made peace through the blood of his cross." The communal meal of the peace offering finds its ultimate expression in 1 Corinthians 10:16-17.'),
('Leviticus', 3, 'adults', 4, 'Why was the prohibition of eating blood ("a perpetual statute") so emphatic in the Levitical system?', 'Blood represents the life (nephesh) of the creature — consuming blood would be symbolically consuming life itself, which belongs to God alone and is set apart for the altar to make atonement (Leviticus 17:11)', 'Blood was forbidden only because it was unhealthy', 'Blood was reserved only for ceremonial washings', 'The prohibition applied only to animal blood in sacrifices', 'a', 'Leviticus 3:17; 17:11 — "For the life of the flesh is in the blood: and I have given it to you upon the altar to make an atonement for your souls: for it is the blood that maketh an atonement for the soul." This theological grounding elevates the blood prohibition far above dietary law.'),
('Leviticus', 3, 'adults', 5, 'Why was the fat of organs (kidneys, caul) given to God rather than eaten?', 'In ancient Near Eastern culture the kidneys and surrounding fat were considered the seat of emotion and deep inner life — offering them to God expressed the dedication of one''s innermost being, not merely external service', 'It was a hygienic precaution only', 'Fat was considered indigestible', 'Only the kidneys were thought to be holy', 'a', 'Leviticus 3:4 — "The two kidneys, and the fat that is on them." The kidneys (kelyoth) in OT anthropology are associated with the deepest inner life (Psalm 7:9 — "God trieth the hearts and reins"). Offering them signifies total interior surrender.'),
('Leviticus', 3, 'adults', 6, 'What is the significance of the peace offering being voluntary rather than obligatory?', 'Voluntary worship from a heart of gratitude is distinct from required atonement — it pictures the believer''s freewill response to grace already received, foreshadowing Paul''s teaching that love cannot be commanded but flows freely from gospel transformation', 'Voluntary offerings were less acceptable than required ones', 'The offering was mandatory at feasts', 'Voluntary offerings were only for priests', 'a', 'Leviticus 3:1 — The peace offering was brought from a heart of shalom, not legal compulsion. Romans 12:1 captures this spirit — "Present your bodies a living sacrifice... which is your reasonable service" — a New Covenant fulfilment of the voluntary peace offering.'),
('Leviticus', 3, 'adults', 7, 'How does the "sweet savour" language connect across the sacrificial system and into the New Testament?', 'The Hebrew reach nichoach ("pleasing aroma") is used across burnt, grain, and peace offerings to describe what is acceptable to God — Paul applies this language directly to Christ''s self-offering in Ephesians 5:2', 'The phrase is only literary decoration', 'The phrase means the smoke kept insects away', 'The language is unique to Leviticus and has no later use', 'a', 'Leviticus 3:5 — "A sweet savour." Ephesians 5:2 — "Christ also hath loved us, and hath given himself for us an offering and a sacrifice to God for a sweetsmelling savour." The identical sacrificial terminology confirms Paul''s Levitical typology.'),
('Leviticus', 3, 'adults', 8, 'What theological tension exists between the peace offering''s joyful communal meal and the holiness requirements surrounding it?', 'The offerer''s joy must not breed carelessness — the offering is "most holy" (cf. 7:1), the fat belongs to God, the blood is untouchable, and the meat must be eaten in time, showing that communion with a holy God requires both joy and reverence', 'The peace offering had no holiness requirements', 'The communal meal was secular and separated from worship', 'Joy and holiness were considered incompatible', 'a', 'Leviticus 7:15-20 — The fellowship meal had strict time limits (same day or next), strict purity requirements, and the penalty for eating while unclean was being "cut off" (v.20). Hebrews 12:28 — "Serve God acceptably with reverence and godly fear."');

-- ═══ Leviticus Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 4, 'kids', 1, 'What kind of sins did the sin offering deal with?', 'Sins done by mistake (ignorance), not knowing it was wrong', 'Only sins done on purpose', 'Only sins against other people', 'Only sins in the camp', 'a', 'Leviticus 4:2 — "Speak unto the children of Israel, saying, If a soul shall sin through ignorance against any of the commandments of the LORD concerning things which ought not to be done, and shall do against any of them."'),
('Leviticus', 4, 'kids', 2, 'What animal did the priest offer as a sin offering for his own sin?', 'A young bullock without blemish', 'A goat', 'A turtledove', 'A lamb', 'a', 'Leviticus 4:3 — "If the priest that is anointed do sin according to the sin of the people; then let him bring for his sin, which he hath sinned, a young bullock without blemish unto the LORD for a sin offering."'),
('Leviticus', 4, 'kids', 3, 'Where was the blood of the sin offering sprinkled for the priest''s sin?', 'Seven times before the LORD, before the veil of the sanctuary', 'On the door of every tent', 'In the river near the camp', 'On the priest''s own head', 'a', 'Leviticus 4:6 — "And the priest shall dip his finger in the blood, and sprinkle of the blood seven times before the LORD, before the veil of the sanctuary."'),
-- Teens
('Leviticus', 4, 'teens', 1, 'What are the four categories of people for whom distinct sin offerings are prescribed in chapter 4?', 'The anointed priest, the whole congregation of Israel, a ruler (prince), and one of the common people', 'Only the priests and the common people', 'Only rulers and the congregation', 'Levites, priests, kings, and foreigners', 'a', 'Leviticus 4:3,13,22,27 — Four distinct sin offering procedures address: the anointed priest (vv.3-12), the whole congregation (vv.13-21), a ruler (vv.22-26), and a common person (vv.27-35), each with different animals and rituals reflecting their spiritual responsibility.'),
('Leviticus', 4, 'teens', 2, 'What happened to the body of the bullock whose blood was brought inside the sanctuary?', 'It was carried outside the camp to a clean place and burned — skin, flesh, head, legs, inwards, and dung', 'It was buried near the tabernacle', 'The priests ate all of it as their portion', 'It was placed in the courtyard overnight', 'a', 'Leviticus 4:11-12 — "And the skin of the bullock, and all his flesh, with his head, and with his legs, and his inwards, and his dung, Even the whole bullock shall he carry forth without the camp unto a clean place... and burn him on the wood with fire."'),
('Leviticus', 4, 'teens', 3, 'What animal was required when a ruler sinned through ignorance?', 'A male kid of the goats without blemish', 'A female lamb', 'A young bullock', 'Two turtledoves', 'a', 'Leviticus 4:23 — "Or if his sin, wherein he hath sinned, come to his knowledge; he shall bring his offering, a kid of the goats, a male without blemish."'),
('Leviticus', 4, 'teens', 4, 'What animal could a common person offer as a sin offering, and what were the options?', 'A female kid of the goats without blemish, or a female lamb without blemish', 'A male goat only', 'Any animal they chose', 'Only a turtledove', 'a', 'Leviticus 4:28,32 — "He shall bring his offering, a kid of the goats, a female without blemish" (v.28) or "if he bring a lamb for a sin offering, he shall bring it a female without blemish" (v.32).'),
('Leviticus', 4, 'teens', 5, 'What phrase describes what would happen to the sin when the proper offering was made?', '"It shall be forgiven him"', '"His debt is cancelled"', '"He is made clean from all filth"', '"His record is erased"', 'a', 'Leviticus 4:26 — "And the priest shall make an atonement for him as concerning his sin, and it shall be forgiven him." The same phrase recurs in vv.20,31,35, emphasising that the offering secured genuine divine forgiveness, not merely ceremonial cleansing.'),
-- Adults
('Leviticus', 4, 'adults', 1, 'What is the Hebrew word for sin offering and why is it significant that it can also mean "sin" itself?', 'Chattath — the same word means both "sin" and "sin offering," theologically expressing that the sacrifice became identified with the sin it bore, a concept Paul applies directly to Christ in 2 Corinthians 5:21', 'It means "purification" with no connection to sin', 'Asham — meaning "guilt"', 'Korban — meaning "a gift brought near"', 'a', 'Leviticus 4:3 — The Hebrew chattath (חַטָּאת) means both "sin" and "sin offering." 2 Corinthians 5:21 — "He hath made him to be sin (hamartian) for us, who knew no sin." Paul uses the identical ambiguity — Christ became the sin offering, fully identified with the sins He bore.'),
('Leviticus', 4, 'adults', 2, 'Why does a greater sin offering (bullock) require burning outside the camp, while lesser offerings are eaten by priests inside?', 'When blood was brought into the sanctuary to cleanse the holy place, the offering could not also be eaten — the greater the defilement addressed, the more complete the separation; this foreshadows Hebrews 13:11-13 where Christ suffered outside the gate', 'It was a practical waste-disposal rule', 'The priests were forbidden from eating any sin offering', 'The bullock was too large for the priests to eat', 'a', 'Leviticus 4:11-12; Hebrews 13:11-13 — "The bodies of those beasts, whose blood is brought into the sanctuary by the high priest for sin, are burned without the camp. Wherefore Jesus also, that he might sanctify the people with his own blood, suffered without the gate."'),
('Leviticus', 4, 'adults', 3, 'What theological principle is embedded in the differentiated offerings by rank (priest → congregation → ruler → commoner)?', 'Greater spiritual authority and privilege entails greater accountability and costlier atonement — the priest who can bring Israel to sin (v.3) must bring the same offering as the whole congregation, showing that leadership''s sin has communal consequences', 'All ranks were treated identically', 'The common person''s sin was the most serious', 'The offerings differed only for practical reasons', 'a', 'Leviticus 4:3 — "If the priest that is anointed do sin according to the sin of the people." The anointed priest''s individual sin is equated with the sin of the whole people, requiring the communal-level offering. James 3:1 — "Be not many masters, knowing that we shall receive the greater condemnation."'),
('Leviticus', 4, 'adults', 4, 'What does the sevenfold blood-sprinkling before the veil signify?', 'Seven is the number of divine completeness — sprinkling blood seven times before the veil of the sanctuary represented complete, divinely sufficient atonement entering into the holy place itself, the closest approach to God''s throne', 'Seven was an arbitrary ritual number', 'It indicated seven days of penance required', 'Seven was the number of priests in attendance', 'a', 'Leviticus 4:6 — "Shall sprinkle of the blood seven times before the LORD, before the veil of the sanctuary." The number seven throughout Leviticus signals divine completeness and perfection. Hebrews 9:12 — "By his own blood he entered in once into the holy place, having obtained eternal redemption for us."'),
('Leviticus', 4, 'adults', 5, 'How does the concept of sins of ignorance in chapter 4 teach about the nature of divine law?', 'God''s law is objective and its violation has real consequences regardless of the offender''s awareness — ignorance does not cancel guilt, it only changes its character; this points to the need for ongoing atonement beyond conscious intentional sin', 'God only punished intentional sins', 'Ignorance completely exempted the offender', 'The law only applied to deliberate actions', 'a', 'Leviticus 4:2 — "If a soul shall sin through ignorance." Numbers 15:30 makes clear that "presumptuous" (deliberate) sin had no sacrificial remedy, only death. The sin offering covers unintentional transgression, showing God''s law is not merely about intent but about conformity to His holy standard.'),
('Leviticus', 4, 'adults', 6, 'What is the significance of the blood being put on the horns of the altar of incense (for priestly/congregational sins) versus the horns of the burnt offering altar (for ruler/commoner sins)?', 'The altar of incense stood before the inner veil — putting blood there brought atonement closer to the Most Holy Place, matching the greater responsibility of those in sacred roles whose sins affect the entire worship system', 'The two altars were interchangeable', 'The incense altar was used only as convenience', 'There was no theological difference', 'a', 'Leviticus 4:7,18 vs. 4:25,30 — The blood on the golden incense altar (inside the Holy Place) for priest and congregation reflects their proximity to the holy things. The blood on the bronze altar (outside) for ruler and common person reflects graduated degrees of approach and responsibility.'),
('Leviticus', 4, 'adults', 7, 'How does the congregational sin offering in chapter 4 anticipate the Day of Atonement in Leviticus 16?', 'Both involve the elders/high priest laying hands on the animal for corporate sin, blood brought before the veil, and the complete burning of the carcass outside the camp — chapter 4 is the template expanded into the annual Yom Kippur ritual', 'The two are entirely different rites with no connection', 'Chapter 16 replaced chapter 4 completely', 'The Day of Atonement did not involve a bullock', 'a', 'Leviticus 4:13-21 — The congregation''s sin offering requires elders to lay hands on the bullock (v.15), blood sprinkled before the veil (v.17), and body burned outside (v:21). Leviticus 16:11,14-16 follows the same pattern for Yom Kippur, confirming chapter 4 as its liturgical prototype.'),
('Leviticus', 4, 'adults', 8, 'What does the laying on of hands (semikhah) on the sin offering accomplish theologically?', 'It effects substitutionary identification — the offerer''s guilt is symbolically transferred to the animal, which then dies in his place; this is the Old Testament foundation of the New Testament doctrine of imputation', 'It was a gesture of appreciation to the priest', 'It only marked the animal as belonging to the offerer', 'It was a ritual to prevent the animal from running away', 'a', 'Leviticus 4:4,24,29,33 — The semikhah (סְמִיכָה) places the sin onto the substitute. Isaiah 53:6 — "The LORD hath laid on him the iniquity of us all." 1 Peter 2:24 — "Who his own self bare our sins in his own body on the tree." The gesture found its ultimate fulfilment at Calvary.');

-- ═══ Leviticus Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 5, 'kids', 1, 'What kind of sin is described when someone touches something unclean without knowing it?', 'A sin of ignorance — they were guilty even though they did not know at the time', 'No sin at all', 'Only a small rule broken', 'A sin that could never be forgiven', 'a', 'Leviticus 5:2-3 — "Or if a soul touch any unclean thing... and it be hid from him; when he knoweth of it, then he shall be guilty."'),
('Leviticus', 5, 'kids', 2, 'What could a very poor person bring instead of animals for the trespass offering?', 'The tenth part of an ephah of fine flour', 'Just water', 'A small piece of cloth', 'Two handfuls of salt', 'a', 'Leviticus 5:11 — "But if he be not able to bring two turtledoves, or two young pigeons, then he that sinned shall bring for his offering the tenth part of an ephah of fine flour for a sin offering."'),
('Leviticus', 5, 'kids', 3, 'What was one of the sins described in chapter 5 that made a person guilty before God?', 'Swearing carelessly with their lips without thinking about what they said', 'Eating too much food', 'Sleeping late in the morning', 'Forgetting a friend''s birthday', 'a', 'Leviticus 5:4 — "Or if a soul swear, pronouncing with his lips to do evil, or to do good, whatsoever it be that a man shall pronounce with an oath, and it be hid from him; when he knoweth of it, then he shall be guilty in one of these."'),
-- Teens
('Leviticus', 5, 'teens', 1, 'What are the four situations that incur guilt and require a trespass offering in chapter 5?', 'Refusing to testify as a witness, touching an unclean thing, touching human uncleanness, and swearing an oath carelessly with the lips', 'Stealing, lying, fighting, and murder', 'Worshipping idols, dishonouring parents, working on the Sabbath, and eating unclean food', 'Only sins against the priests', 'a', 'Leviticus 5:1-4 — Four cases: (1) hearing a public oath and withholding testimony (v.1), (2) touching an unclean animal carcass (v.2), (3) touching human uncleanness (v.3), (4) speaking a rash oath (v.4). Each requires confession and a sin offering.'),
('Leviticus', 5, 'teens', 2, 'What must the guilty person do before bringing the offering?', 'Confess the sin he has committed', 'Perform seven days of fasting', 'Go tell the elders at the city gate', 'Wash in the river seven times', 'a', 'Leviticus 5:5 — "And it shall be, when he shall be guilty in one of these things, that he shall confess that he hath sinned in that thing."'),
('Leviticus', 5, 'teens', 3, 'What was the graded provision for those who could not afford a lamb for the trespass offering?', 'Two turtledoves or two young pigeons (one for sin offering, one for burnt offering); or if still too poor, one-tenth ephah of fine flour', 'A single turtledove was always sufficient', 'There was no provision for the poor', 'Only a lamb was acceptable', 'a', 'Leviticus 5:7,11 — "And if he be not able to bring a lamb, then he shall bring... two turtledoves, or two young pigeons" (v.7); "But if he be not able to bring two turtledoves... then he shall bring... the tenth part of an ephah of fine flour" (v.11).'),
('Leviticus', 5, 'teens', 4, 'How was the flour offering for the very poor different from the usual grain offering?', 'No oil or frankincense was put on it, because it was for sin — it was not to be sweetened, only the memorial portion was burned, and the rest went to the priest', 'It had double the oil applied', 'It was offered on a different altar', 'It was given entirely to the priest with nothing burned', 'a', 'Leviticus 5:11 — "He shall put no oil upon it, neither shall he put any frankincense thereon: for it is a sin offering." The absence of oil and frankincense removes the elements symbolising joy and fragrance, emphasising the gravity of the sin being addressed.'),
('Leviticus', 5, 'teens', 5, 'What does the term "trespass" (asham) describe in chapter 5 compared to the sin offering (chattath)?', 'The asham addresses specific acts of violation where a personal debt or wrong must be compensated — it focuses on what was taken from God or man, requiring restitution alongside the sacrifice', 'Asham and chattath are identical in meaning', 'Asham only applied to crimes against other people', 'Asham was only used by the high priest', 'a', 'Leviticus 5:14-19 — The asham (guilt/trespass offering) appears for sins against "holy things of the LORD" (vv.15-16) and sins done "in ignorance" yet still carrying objective guilt (vv.17-19). It addresses the debt dimension of sin, not just the defilement.'),
-- Adults
('Leviticus', 5, 'adults', 1, 'What is theologically significant about the guilt that accrues even before the person "knows" of it (verse 3)?', 'It reveals that sin has objective consequences independent of subjective awareness — a person is guilty before God from the moment of the transgression, not from the moment of discovery; this underscores humanity''s need for ongoing priestly intercession', 'Guilt only begins when the person becomes aware', 'Unconscious sins were not real sins', 'The law was only about external behaviour', 'a', 'Leviticus 5:3-4 — "It be hid from him; when he knoweth of it, then he shall be guilty." The guilt preceded the knowledge. Romans 3:19-20 — "By the law is the knowledge of sin." Sin is a condition, not merely a series of conscious choices.'),
('Leviticus', 5, 'adults', 2, 'What is the significance of confession (verbal acknowledgment) being required before the offering in verse 5?', 'Confession moves atonement from mere ritual to genuine repentance — it requires the offender to name and own the specific sin, prefiguring the New Testament pattern of 1 John 1:9 where confession precedes cleansing', 'Confession was a mere formality without spiritual meaning', 'Confession replaced the need for an offering', 'Confession was optional for minor sins', 'a', 'Leviticus 5:5 — "He shall confess that he hath sinned in that thing." 1 John 1:9 — "If we confess our sins, he is faithful and just to forgive us our sins, and to cleanse us from all unrighteousness." The pattern of specific, verbal, genuine confession runs from Leviticus through the New Testament.'),
('Leviticus', 5, 'adults', 3, 'How does the accommodation for the poor (flour offering) reflect the character of God?', 'God provides a sacrificial path for even the most destitute — no one is excluded from atonement because of poverty, revealing His desire that all have access to forgiveness regardless of economic status; this anticipates the gospel''s universal offer', 'The poor were excluded from full atonement', 'The flour offering was less effective than the lamb', 'God''s grace had limits based on wealth', 'a', 'Leviticus 5:11 — The provision of flour for the very poor ensures access to atonement is not stratified by wealth. This reflects the same character seen in the tiered burnt offering (ch.1). Luke 4:18 — "He hath anointed me to preach the gospel to the poor."'),
('Leviticus', 5, 'adults', 4, 'What does the removal of oil and frankincense from the flour sin offering teach about the theology of sin?', 'Oil (the Spirit''s anointing) and frankincense (sweet savour of prayer) were tokens of divine favour and fellowship — their absence from the sin offering signals that the primary note is not fellowship but the gravity and cost of transgression', 'Their removal was only practical', 'Oil and frankincense were unrelated to spiritual meaning', 'The priest accidentally omitted them', 'a', 'Leviticus 5:11 — "He shall put no oil upon it, neither shall he put any frankincense thereon." Contrast this with the grain offering (2:1) which included both. The stripped-down flour offering for sin is deliberately austere, communicating that sin ruptures the joyful communion that oil and frankincense represent.'),
('Leviticus', 5, 'adults', 5, 'How does the guilty person''s sin against "holy things of the LORD" (verse 15) introduce a new category of trespass?', 'It addresses the misuse or misappropriation of what has been consecrated to God — tithes, firstfruits, sacred donations — and requires both the sacrifice and a full restitution plus one-fifth penalty, showing that holy things demand special accountability', 'Holy things were treated exactly like ordinary sins', 'Only intentional theft from the tabernacle was covered', 'The offering alone was sufficient without restitution', 'a', 'Leviticus 5:15-16 — "If a soul commit a trespass, and sin through ignorance, in the holy things of the LORD... he shall add the fifth part thereto." Unwitting shortfall in what belongs to God still requires not only atonement but compensatory restitution, revealing God''s proprietary right over what is consecrated.'),
('Leviticus', 5, 'adults', 6, 'What does the phrase "he wist it not, yet is he guilty" (verse 17) reveal about the relationship between knowledge and moral culpability?', 'It establishes that objective moral guilt exists independently of subjective awareness — the standard is God''s holy law, not human consciousness; this directly counters the modern idea that sincerity of intention is the sole measure of moral responsibility', 'Ignorance fully excused the offender from guilt', 'God only judged known sins', 'Moral guilt required deliberate malice', 'a', 'Leviticus 5:17 — "Though he wist it not, yet is he guilty, and shall bear his iniquity." This principle cuts against situational ethics. Acts 17:30 — "And the times of this ignorance God winked at; but now commandeth all men every where to repent."'),
('Leviticus', 5, 'adults', 7, 'How does the trespass offering (asham) compare to the New Testament concept of propitiation?', 'The asham covered the debt dimension of sin before a holy God — it satisfied divine justice by substitution, paralleling Romans 3:25 where Christ is set forth as a hilasterion (propitiation/mercy seat), satisfying God''s wrath through His blood', 'The asham only addressed social infractions', 'Propitiation is a different concept with no Levitical background', 'The asham was replaced by the sin offering and had no NT connection', 'a', 'Leviticus 5:6 — "He shall bring his trespass offering unto the LORD for his sin which he hath sinned." Romans 3:25 — "Whom God hath set forth to be a propitiation through faith in his blood." The asham''s satisfying of divine justice foreshadows the propitiation Christ accomplished.'),
('Leviticus', 5, 'adults', 8, 'What is the literary and theological structure of Leviticus 5 in relation to chapters 4 and 6?', 'Chapter 4 establishes the sin offering (chattath) for unintentional sins against God''s commandments; chapter 5 introduces the trespass offering (asham) for specific violations requiring restitution; chapter 6 continues the asham for sins against neighbour — together forming a triad covering sin''s full dimensions', 'Chapters 4-6 are identical in content', 'Chapter 5 contradicts chapter 4', 'The chapters have no structural relationship', 'a', 'The progression from chattath (4) to asham (5-6) mirrors the two dimensions of sin: impurity/defilement (requires cleansing) and debt/violation (requires payment + restitution). Together they anticipate what Hebrews 9:14 describes — Christ whose blood both "purge[s] your conscience" and redeems the soul.');

-- ═══ Leviticus Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 6, 'kids', 1, 'What was the fire on the altar of burnt offering never allowed to do?', 'Go out — it had to burn continually every day', 'Burn too brightly', 'Touch the ground outside the altar', 'Spread to the tabernacle curtains', 'a', 'Leviticus 6:13 — "The fire shall ever be burning upon the altar; it shall never go out."'),
('Leviticus', 6, 'kids', 2, 'What did the priest have to put on before he could take away the ashes from the altar?', 'His linen garment and linen breeches', 'His golden crown', 'His colourful outer robe', 'His sandals and belt', 'a', 'Leviticus 6:10 — "And the priest shall put on his linen garment, and his linen breeches shall he put upon his flesh, and take up the ashes which the fire hath consumed with the burnt offering on the altar."'),
('Leviticus', 6, 'kids', 3, 'Who could eat the grain offering that was left over after the priests burned part of it?', 'Aaron and his sons (the priests)', 'Anyone in the camp who was hungry', 'Only the high priest alone', 'The Levites who carried the tabernacle', 'a', 'Leviticus 6:16 — "And the remainder thereof shall Aaron and his sons eat: with unleavened bread shall it be eaten in the court of the tabernacle of the congregation."'),
-- Teens
('Leviticus', 6, 'teens', 1, 'What specific sins against a neighbour does the trespass offering in chapter 6 address?', 'Lying about a deposit or pledge, robbing, deceiving, finding lost property and lying about it, or swearing falsely in any such matters', 'Only theft of large amounts', 'Only sins against the priests', 'Murder and physical violence', 'a', 'Leviticus 6:2-3 — "If a soul sin, and commit a trespass against the LORD, and lie unto his neighbour in that which was delivered him to keep, or in fellowship, or in a thing taken away by violence, or hath deceived his neighbour; Or have found that which was lost, and lieth concerning it, and sweareth falsely."'),
('Leviticus', 6, 'teens', 2, 'What must the guilty person do in addition to bringing the trespass offering?', 'Restore the principal amount plus one-fifth to the person they sinned against, on the same day they bring the offering', 'Bring a separate gift to the priests', 'Confess publicly before the whole congregation', 'Fast for three days before the offering', 'a', 'Leviticus 6:4-5 — "He shall restore that which he took violently away... or the lost thing which he found, Or all that about which he hath sworn falsely; he shall even restore it in the principal, and shall add the fifth part more thereto."'),
('Leviticus', 6, 'teens', 3, 'What instructions were given about the priest''s garments when removing ashes from the altar?', 'He was to change from his linen garments into other garments to carry the ashes outside the camp to a clean place', 'He could wear any garments he liked', 'He was to remove all garments and wash before touching the ashes', 'He had to wear the golden ephod', 'a', 'Leviticus 6:10-11 — "The priest shall put on his linen garment... and take up the ashes... and he shall put off his garments, and put on other garments, and carry forth the ashes without the camp unto a clean place."'),
('Leviticus', 6, 'teens', 4, 'What was the daily grain offering of the high priest, and when was it offered?', 'A tenth of an ephah of fine flour as a perpetual grain offering — half in the morning and half in the evening', 'A whole ephah of flour only at sunrise', 'The grain offering of Aaron was offered only on the Sabbath', 'A small offering given once a week', 'a', 'Leviticus 6:20 — "This is the offering of Aaron and of his sons, which they shall offer unto the LORD in the day when he is anointed; the tenth part of an ephah of fine flour for a meat offering perpetual, half of it in the morning, and half thereof at night."'),
('Leviticus', 6, 'teens', 5, 'Why was the grain offering of the priest burned completely rather than partially eaten by him?', 'Because no sin offering for a priest could be eaten — it must be wholly burned, for a priest''s offering on behalf of himself is entirely for the LORD', 'Because the priest was too busy to eat it', 'Because the grain offering was always fully burned for everyone', 'Because the priests preferred not to eat flour', 'a', 'Leviticus 6:22-23 — "And the priest of his sons that is anointed in his stead shall offer it: it is a statute for ever unto the LORD; it shall be wholly burnt. For every meat offering for a priest shall be wholly burnt: it shall not be eaten."'),
-- Adults
('Leviticus', 6, 'adults', 1, 'What is the theological significance of the perpetual altar fire that must "never go out"?', 'It represents God''s unceasing holiness and the constant need for atonement — the never-dying fire also foreshadows the "unquenchable fire" of divine judgment (Matthew 3:12) and the perpetual intercession of Christ (Hebrews 7:25)', 'It was purely practical to maintain warmth in the desert', 'The fire only burned during worship hours', 'The perpetual fire was unique to Tabernacle and not spiritually meaningful', 'a', 'Leviticus 6:13 — "The fire shall ever be burning upon the altar; it shall never go out." The original fire in Leviticus 9:24 came from God Himself. Maintaining it perpetually acknowledged that divine holiness never diminishes and the sacrifice is never fully complete until Christ (Hebrews 10:14).'),
('Leviticus', 6, 'adults', 2, 'How does the restitution-plus-one-fifth requirement (6:5) integrate law and grace?', 'The sacrifice (grace — forgiveness of guilt) does not cancel the obligation to make the wronged party whole (law — justice), teaching that genuine repentance involves both vertical (God-ward) and horizontal (man-ward) restoration', 'Bringing the offering was sufficient without restitution', 'Restitution replaced the need for a sacrifice', 'The one-fifth penalty was a deterrent only with no spiritual meaning', 'a', 'Leviticus 6:5-6 — The guilty party must restore + 20% to the neighbour AND bring the ram of trespass offering. This double obligation embodies what Jesus expressed in Matthew 5:23-24 — reconcile with your brother, then bring your offering.'),
('Leviticus', 6, 'adults', 3, 'What is the significance of the priest wearing linen (not wool) for the ash removal service?', 'Linen was the fabric of humility and service — not the splendour of the golden ephod — signifying that the most menial tasks of priestly service (ash removal) were still to be performed with consecrated reverence, no task being beneath holiness', 'Linen was used only for practical hygiene reasons', 'The fabric choice was a cultural preference only', 'Linen indicated the priest was performing a less important task', 'a', 'Leviticus 6:10 — "The priest shall put on his linen garment." Ezekiel 44:17-18 later specifies that linen prevents sweat — no sweat in God''s presence, no effort of the flesh. The linen priestly garments contrast with the elaborate vestments of the high priest for intercession.'),
('Leviticus', 6, 'adults', 4, 'What does the changing of garments between ash removal and carrying ashes outside the camp teach?', 'The garments worn in the sanctuary''s holy service are not to mingle with the outside world — sanctified things must be kept distinct from common things, a principle running through all Levitical purity laws and into NT holiness teaching', 'The garment change was only for cleanliness', 'The two sets of garments had no symbolic difference', 'The outer garments were superior to the linen ones', 'a', 'Leviticus 6:11 — "He shall put off his garments, and put on other garments, and carry forth the ashes." Ezekiel 44:19 elaborates on this principle: "When they go forth into the utter court to the people, they shall put off their garments wherein they ministered." Holy service and common life require distinct moral registers.'),
('Leviticus', 6, 'adults', 5, 'Why must the priests'' grain offering be wholly burned rather than eaten, while the people''s grain offering is partially eaten by the priests?', 'A priest cannot be atonement-beneficiary for himself through his own office — he cannot eat what is offered on his own behalf, for that would collapse the mediatorial distinction between offerer and priest', 'Priests were forbidden all food', 'The priests'' grain offering was of lower quality', 'There was no real difference in the rules', 'a', 'Leviticus 6:22-23 — "Every meat offering for a priest shall be wholly burnt: it shall not be eaten." This principle extends to the high priest''s annual sin offering (16:27) — the mediator cannot benefit from his own mediation while in that role, pointing to Christ who "offered up himself" without personal need (Hebrews 7:27).'),
('Leviticus', 6, 'adults', 6, 'How does the grain offering being eaten in the tabernacle courtyard (not elsewhere) model the principle of sacred space?', 'God''s holy things must be consumed within the sphere of His appointed presence — the sacred is not to bleed indiscriminately into common life; this models what Hebrews 13:10 calls "an altar, whereof they have no right to eat which serve the tabernacle"', 'Location was irrelevant to the holiness of the meal', 'The courtyard restriction was logistical only', 'The priests could eat anywhere in the camp', 'a', 'Leviticus 6:16 — "With unleavened bread shall it be eaten in the court of the tabernacle of the congregation." The holy things are eaten within the boundary of the sacred precinct, maintaining the distinction between the holy and the common (10:10).'),
('Leviticus', 6, 'adults', 7, 'What New Testament concept does the trespass offering (asham) for sins against a neighbour (6:1-7) most directly foreshadow?', 'The restoration of Zacchaeus (Luke 19:8) where genuine conversion produced immediate fourfold restitution — true repentance repairs not just the God-ward offence but the neighbour-ward damage, fulfilling the spirit of Leviticus 6', 'Only the cross with no horizontal dimension', 'Only future eschatological judgment', 'Church discipline procedures in Matthew 18', 'a', 'Leviticus 6:5; Luke 19:8 — Zacchaeus: "If I have taken any thing from any man by false accusation, I restore him fourfold." His restoration exceeded the Levitical requirement (100% + 20%) with the fourfold restitution prescribed for theft (Exodus 22:1), demonstrating how the gospel produces the fullest expression of the law.'),
('Leviticus', 6, 'adults', 8, 'How does Leviticus 6:12-13 relate to Romans 12:11 in the New Covenant?', 'The perpetual fire requiring daily maintenance typifies the believer''s calling to keep spiritual fervour alive through daily discipline — Romans 12:11 ("fervent in spirit") uses zeo (to boil/burn) as a direct spiritual analogue to the priestly maintenance of divine fire', 'There is no connection between the two passages', 'Romans 12 abolishes the Levitical altar fire principle', 'Romans 12:11 refers only to missionary activity', 'a', 'Leviticus 6:12 — "And the fire upon the altar shall be burning in it; it shall not be put out." Romans 12:11 — "Not slothful in business; fervent in spirit; serving the Lord." The Greek zeontes (burning/boiling) mirrors the priestly imperative to tend the holy fire of devotion daily.');

-- ═══ Leviticus Chapter 7 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 7, 'kids', 1, 'How quickly did the peace offering need to be eaten after it was offered as a thanksgiving?', 'On the same day it was offered — none of it could be left until the morning', 'It could be saved for a whole week', 'It could be kept for three days', 'It only needed to be eaten before sunset the next day', 'a', 'Leviticus 7:15 — "And the flesh of the sacrifice of his peace offerings for thanksgiving shall be eaten the same day that it is offered; he shall not leave any of it until the morning."'),
('Leviticus', 7, 'kids', 2, 'What would happen to a person who ate the fat of an ox, sheep, or goat?', 'They would be cut off from their people', 'They would have to bring an extra offering', 'They would be made to leave the camp for one day', 'Nothing would happen to them', 'a', 'Leviticus 7:25 — "For whosoever eateth the fat of the beast, of which men offer an offering made by fire unto the LORD, even the soul that eateth it shall be cut off from his people."'),
('Leviticus', 7, 'kids', 3, 'What was the wave offering?', 'A portion of the offering waved before the LORD and then given to the priests', 'An offering thrown into a river', 'An offering carried to the mountain top', 'An offering given to the poor outside the camp', 'a', 'Leviticus 7:30 — "His own hands shall bring the offerings of the LORD made by fire, the fat with the breast, it shall he bring, that the breast may be waved for a wave offering before the LORD."'),
-- Teens
('Leviticus', 7, 'teens', 1, 'What were the three types of peace offerings described in chapter 7?', 'Thanksgiving, a vow, and a freewill offering', 'Morning, noon, and evening offerings', 'Annual, monthly, and weekly offerings', 'Harvest, firstfruits, and Sabbath offerings', 'a', 'Leviticus 7:12-16 — Three types of peace offerings are distinguished: thanksgiving (todah, vv.12-15), fulfilling a vow (neder, v.16), and a freewill offering (nedavah, v.16), each with slightly different time limits for consuming the flesh.'),
('Leviticus', 7, 'teens', 2, 'What happened to meat from the peace offering that was left until the third day?', 'It was to be burned with fire and was called an abomination — eating it would not be accepted and the eater bore iniquity', 'It could still be eaten if it looked fresh', 'It was given to the poor of the city', 'It was stored in the tabernacle storehouse', 'a', 'Leviticus 7:17-18 — "But what remaineth of the flesh of the sacrifice on the third day shall be burnt with fire. And if any of the flesh of the sacrifice of his peace offerings be eaten at all on the third day, it shall not be accepted, neither shall it be imputed unto him that offereth it: it shall be an abomination."'),
('Leviticus', 7, 'teens', 3, 'What was the "heave offering" and who received it?', 'The right shoulder of the peace offering, heaved upward before the LORD, and given to the officiating priest as his portion', 'The skin of the burnt offering', 'The first loaf of bread from the grain offering', 'The kidney fat offered on behalf of the tribe', 'a', 'Leviticus 7:32-34 — "And the right shoulder shall ye give unto the priest for an heave offering of the sacrifices of your peace offerings. He among the sons of Aaron, that offereth the blood of the peace offerings, and the fat, shall have the right shoulder for his part."'),
('Leviticus', 7, 'teens', 4, 'What would happen to a person who ate flesh from the peace offering while being unclean?', 'That person would be cut off from their people', 'They would only need to wash in water', 'Nothing — the person was not responsible for their uncleanness', 'They would have to repeat the offering', 'a', 'Leviticus 7:20-21 — "But the soul that eateth of the flesh of the sacrifice of peace offerings, that pertain unto the LORD, having his uncleanness upon him, even that soul shall be cut off from his people."'),
('Leviticus', 7, 'teens', 5, 'What was waved before the LORD from the peace offering, and what happened to it afterward?', 'The breast was waved as a wave offering and then became the portion of Aaron and his sons to eat', 'The breast was burned completely on the altar', 'The breast was returned to the offerer', 'The breast was buried in the ground', 'a', 'Leviticus 7:30-31 — "The fat with the breast, it shall he bring, that the breast may be waved for a wave offering before the LORD. And the priest shall burn the fat upon the altar: but the breast shall be Aaron''s and his sons''.'),
-- Adults
('Leviticus', 7, 'adults', 1, 'What is the Hebrew word for the thanksgiving peace offering and how does it illuminate NT worship?', 'Todah — meaning praise or thanksgiving; the todah offering is the Old Testament root of Hebrews 13:15 — "By him therefore let us offer the sacrifice of praise to God continually, that is, the fruit of our lips giving thanks (eucharistia) to his name"', 'Zebach — meaning slaughter with no thanksgiving connotation', 'Minchah — meaning tribute only', 'Shelamim — meaning peace with no thanksgiving dimension', 'a', 'Leviticus 7:12 — The todah (תּוֹדָה) is a peace offering specifically for thanksgiving. Psalm 50:14,23 — "Offer unto God thanksgiving (todah)... Whoso offereth praise (todah) glorifieth me." The NT eucharistia (thankfulness) and Eucharist (Lord''s Supper) are its direct spiritual descendants.'),
('Leviticus', 7, 'adults', 2, 'What is the typological significance of the "abomination" (pigul) of meat eaten on the third day?', 'The third-day language is eschatologically significant — the offering''s validity was exhausted; only a fresh, timely appropriation was acceptable, foreshadowing that Christ''s resurrection on the third day inaugurated a new era making all old sacrifices obsolete', 'It was a practical food safety rule only', 'The third day had no typological meaning', 'The abomination only applied to the thanksgiving offering', 'a', 'Leviticus 7:18 — "If any of the flesh... be eaten at all on the third day, it shall be an abomination." The Hebrew pigul (פִּגּוּל) denotes that which is foul and rejected. The third-day motif (Hosea 6:2, 1 Corinthians 15:4) signals divine completion and resurrection, rendering the old order''s stale offerings abominable.'),
('Leviticus', 7, 'adults', 3, 'Why is the prohibition of blood repeated here (7:26-27) after its earlier statement in chapter 3?', 'The blood prohibition is re-emphasised because the communal peace offering meal created the greatest temptation and opportunity to consume blood — the repetition underscores that the sanctity of life (nephesh is in the blood) is non-negotiable even in festive contexts', 'It was an editorial mistake in the text', 'The earlier prohibition only applied to priests', 'Chapter 7 introduces a completely new rule', 'a', 'Leviticus 7:26-27 — "Moreover ye shall eat no manner of blood, whether it be of fowl or of beast, in any of your dwellings." The joyful communal meal of the peace offering posed the greatest risk of casual blood consumption; hence the re-emphasis. Acts 15:20 carried this prohibition into the New Covenant church.'),
('Leviticus', 7, 'adults', 4, 'What is the wave offering''s theological function, and how does it differ from the heave offering?', 'The wave offering (tenufah) was waved horizontally before the LORD — presented to God and returned to the priests — symbolising presentation to God and acceptance back from Him. The heave offering (terumah) was lifted vertically, presenting the choicest elevated to God', 'The two terms are completely synonymous', 'The heave offering went to the poor while the wave offering burned', 'The wave offering was seasonal; the heave offering was daily', 'a', 'Leviticus 7:30,32 — Tenufah (wave) and terumah (heave/elevation) together represent the two dimensions of priestly mediation: bringing what belongs to God back into sanctified use for His servants. Exodus 29:27 first established both categories at the priests'' ordination.'),
('Leviticus', 7, 'adults', 5, 'What does the cutting off (karet) penalty for eating fat or blood reveal about the severity of these prohibitions?', 'Karet ("cutting off") is the most severe non-capital penalty in the Torah — divine excision from the covenant community, potentially including premature death by God''s direct judgment, showing these prohibitions guarded the very heart of covenant theology', 'Karet simply meant social exclusion for one year', 'Karet was only applied to deliberate murder', 'Karet was a minor disciplinary measure', 'a', 'Leviticus 7:25,27 — "Shall be cut off from his people." The karet penalty appears ~36 times in Leviticus for the most serious covenant violations. Eating blood directly violated the life-is-in-the-blood theology of 17:11 — the foundational premise of all atonement theology.'),
('Leviticus', 7, 'adults', 6, 'How does chapter 7 function as a summary and completion of the sacrificial legislation begun in chapters 1-6?', 'Verses 37-38 provide an explicit summary formula ("This is the law of the burnt offering, of the meat offering, and of the sin offering, and of the trespass offering, and of the consecrations, and of the sacrifice of the peace offerings") — forming a literary inclusio concluding the first major Levitical law unit', 'Chapter 7 introduces entirely new material not in chapters 1-6', 'The summary was added by a later editor with no structural purpose', 'Chapters 1-7 have no literary relationship', 'a', 'Leviticus 7:37-38 — "This is the law of the burnt offering, of the meat offering, and of the sin offering, and of the trespass offering... Which the LORD commanded Moses in mount Sinai." This colophon closes the sacrificial law section (chs.1-7), a classic Ancient Near Eastern literary device marking the end of a legal collection.'),
('Leviticus', 7, 'adults', 7, 'What is the significance of the peace offering''s communal meal being shared with sons, daughters, and menservants (Deuteronomy 12:12,18)?', 'The peace offering''s shared table extended divine fellowship to the entire household including servants — portraying that shalom with God overflows into human community, anticipating the eschatological banquet where all nations feast at God''s table (Isaiah 25:6)', 'The communal meal was irrelevant to the offering''s theological meaning', 'Women and servants were excluded from the peace offering meal', 'The meal was only for adult male Israelites', 'a', 'Deuteronomy 12:18 instructs eating peace offerings "before the LORD thy God" with sons, daughters, servants, and the Levite. The peace offering''s shared meal pictures covenant community flourishing — a foretaste of the Marriage Supper of the Lamb (Revelation 19:9).'),
('Leviticus', 7, 'adults', 8, 'How does Paul''s argument in 1 Corinthians 10:18 about "partakers of the altar" draw on Leviticus 7''s peace offering theology?', 'Paul argues that eating sacrificial food creates communion with that which the sacrifice represents — just as Israelites partaking of the peace offering altar shared in the covenant with God, so eating at an idol''s table creates communion with demons', 'Paul''s argument is unrelated to Levitical sacrifice', 'Paul was arguing only about physical health in 1 Corinthians 10', 'Paul denied the relevance of Levitical food laws to his argument', 'a', 'Leviticus 7:15-18; 1 Corinthians 10:18 — "Behold Israel after the flesh: are not they which eat of the sacrifices partakers of the altar?" Paul''s argument depends entirely on the Levitical principle that eating the peace offering created covenantal communion with God — the same principle that makes idol feast participation spiritually catastrophic.');

-- ═══ Leviticus Chapter 8 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 8, 'kids', 1, 'Who did Moses consecrate (set apart) as priests in chapter 8?', 'Aaron and his sons', 'The twelve elders of Israel', 'The tribe of Judah only', 'Joshua and Caleb', 'a', 'Leviticus 8:2 — "Take Aaron and his sons with him, and the garments, and the anointing oil, and a bullock for the sin offering, and two rams, and a basket of unleavened bread."'),
('Leviticus', 8, 'kids', 2, 'What did Moses pour on Aaron''s head to set him apart as high priest?', 'The anointing oil', 'Water from the basin', 'Blood from the altar', 'Wine from the offerings', 'a', 'Leviticus 8:12 — "And he poured of the anointing oil upon Aaron''s head, and anointed him, to sanctify him."'),
('Leviticus', 8, 'kids', 3, 'How many days did Aaron and his sons have to stay at the tabernacle door during their ordination?', 'Seven days', 'Three days', 'Forty days', 'One day', 'a', 'Leviticus 8:33 — "And ye shall not go out of the door of the tabernacle of the congregation in seven days, until the days of your consecration be at an end: for seven days shall he consecrate you."'),
-- Teens
('Leviticus', 8, 'teens', 1, 'What items did Moses use to clothe Aaron and what special object did he place over the breastplate?', 'The coat, girdle, robe, ephod, curious girdle of the ephod, and the breastplate; the Urim and Thummim were put in the breastplate', 'Only the golden crown and linen coat', 'Only the ephod and the golden plate on his head', 'The full linen garments of the common priests', 'a', 'Leviticus 8:7-8 — "And he put upon him the coat, and girded him with the girdle, and clothed him with the robe, and put the ephod upon him... And he put in the breastplate also the Urim and the Thummim."'),
('Leviticus', 8, 'teens', 2, 'What was written on the golden plate placed on Aaron''s mitre?', 'Holiness to the LORD', 'Aaron High Priest of Israel', 'The names of the twelve tribes', 'The law of Moses', 'a', 'Leviticus 8:9; Exodus 28:36 — "And he put the mitre upon his head; also upon his mitre, even upon his forefront, did he put the golden plate, the holy crown; as the LORD commanded Moses." Exodus 28:36 — "HOLINESS TO THE LORD."'),
('Leviticus', 8, 'teens', 3, 'What three types of offerings were made during the ordination of Aaron and his sons?', 'A sin offering (bullock), a burnt offering (ram), and the ram of consecration (ordination offering)', 'Only a sin offering and a peace offering', 'A burnt offering, grain offering, and drink offering only', 'Two sin offerings and one burnt offering', 'a', 'Leviticus 8:14-29 — Three offerings mark the ordination: the bullock for a sin offering (vv.14-17), the first ram as a burnt offering (vv.18-21), and the second ram as the consecration offering (vv.22-29).'),
('Leviticus', 8, 'teens', 4, 'What was done with the blood of the ram of consecration in a distinctive way not done in other offerings?', 'Moses put blood on the right ear, right thumb, and right great toe of Aaron and his sons, then sprinkled blood on the altar round about', 'Only the altar was touched with blood', 'The blood was poured in a circle around the priests', 'The blood was applied to the curtain of the tabernacle', 'a', 'Leviticus 8:23-24 — "And Moses took of the blood of it, and put it upon the tip of Aaron''s right ear, and upon the thumb of his right hand, and upon the great toe of his right foot... and sprinkled the blood upon the altar round about."'),
('Leviticus', 8, 'teens', 5, 'What was waved as a wave offering before the LORD during the ordination of Aaron?', 'The breast of the ram of consecration, along with the fat portions and one unleavened cake, one oiled cake, and one wafer', 'Only the left leg of the ram', 'Only the grain offering without any meat', 'The golden crown of Aaron', 'a', 'Leviticus 8:27-29 — "And he put all upon Aaron''s hands, and upon his sons'' hands, and waved them for a wave offering before the LORD. And Moses took them from off their hands, and burnt them on the altar upon the burnt offering: they were consecrations for a sweet savour."'),
-- Adults
('Leviticus', 8, 'adults', 1, 'What is the Hebrew term for consecration/ordination (milu''im) and what does it literally mean?', 'Milu''im — from male'' meaning "to fill" or "filling" — the ordination filling the hands of the priest with his office and authority; it is the priest''s formal investiture with his sacred function', 'Qadash — meaning only "to be set apart"', 'Semikhah — meaning "laying on of hands only"', 'Birkat — meaning "a blessing"', 'a', 'Leviticus 8:33 — "Until the days of your consecration (milu''im) be at an end." The Hebrew milu''im (מִלֻּאִים) means "fillings" — the priest''s hands are filled with the offering (Exodus 29:24), symbolising that he is now authorised and equipped to handle holy things on behalf of the people.'),
('Leviticus', 8, 'adults', 2, 'What does the blood applied to the ear, thumb, and toe of the priests signify typologically?', 'The ear represents hearing/obeying God''s word; the right thumb represents consecrated service and action; the right great toe represents walking in God''s ways — together they signify the total person consecrated to God''s service in word, deed, and walk', 'The application was purely ritualistic with no symbolic meaning', 'It only prevented the priests from touching unclean things', 'It signified the priests'' physical purity only', 'a', 'Leviticus 8:23-24 — The same three-point blood application appears for cleansed lepers (14:14), connecting priestly consecration with purification. The right side emphasised strength and authority. The ear (hearing), hand (doing), foot (walking) represent the whole person consecrated for holy service (Romans 12:1).'),
('Leviticus', 8, 'adults', 3, 'How does the ordination of Aaron foreshadow Christ''s anointing and high priestly role?', 'Aaron was anointed with oil (the Spirit), offered sacrifices for sin (first for himself, then for people), and entered a seven-day consecration period — Christ received the Spirit without measure (John 3:34), was sinless, and entered His heavenly priesthood by His own blood (Hebrews 5:4-6)', 'Aaron and Christ have no priestly connection', 'Christ''s priesthood follows the order of Aaron exactly', 'The Aaronic and Melchizedek priesthoods serve identical functions', 'a', 'Hebrews 5:4-6 — "No man taketh this honour unto himself... Christ glorified not himself to be made an high priest." Leviticus 8:12 anointing oil → Luke 4:18 ("The Spirit of the LORD is upon me"). But unlike Aaron (8:14 — needing his own sin offering), Christ "needeth not daily... to offer up sacrifice, first for his own sins" (Hebrews 7:27).'),
('Leviticus', 8, 'adults', 4, 'What is the significance of the entire congregation being assembled at the tabernacle door (verse 3) for the ordination?', 'Priestly consecration is not a private transaction but a public, corporate, witnessed event — the whole community of Israel is the context and beneficiary of priestly service, establishing that the priesthood exists for the people, not for itself', 'The assembly was only for logistical organisation', 'The congregation played no theological role', 'Only the elders and leaders were needed to witness', 'a', 'Leviticus 8:3-4 — "Gather thou all the congregation together... And Moses did as the LORD commanded him; and the assembly was gathered together." The public nature of ordination establishes accountability — the priest serves a congregation that witnessed his consecration and must hold him to that standard.'),
('Leviticus', 8, 'adults', 5, 'Why were Aaron and his sons required to remain at the tabernacle door for seven full days?', 'The seven-day period was a period of transition and consecration — moving from common to holy status required sustained ritual boundary maintenance, and any departure would break the consecration process and result in death', 'Seven days was only a convenient time period', 'They could leave at night as long as they returned by morning', 'The seven days was an educational period to learn offerings', 'a', 'Leviticus 8:33,35 — "Ye shall not go out... for seven days... Therefore shall ye abide at the door... day and night seven days, and keep the charge of the LORD, that ye die not." The seven-day threshold period mirrors creation''s week and signals that a new order of holy service was being established.'),
('Leviticus', 8, 'adults', 6, 'What is the typological significance of Moses performing the ordination rather than Aaron himself?', 'No priest can consecrate himself — Moses, acting as God''s representative, consecrates Aaron, establishing the principle that sacred authority is conferred from outside and above, not assumed from within; this points to Christ''s appointment by the Father (Hebrews 5:5)', 'Moses took the role because Aaron was too old', 'The ordination could have been self-administered', 'Moses and Aaron were interchangeable in their roles', 'a', 'Leviticus 8:10-13 — Moses anoints, dresses, and consecrates Aaron. Hebrews 5:5 — "Christ glorified not himself to be made an high priest; but he that said unto him, Thou art my Son, to day have I begotten thee." The Father''s appointment, not self-elevation, is the pattern for all legitimate spiritual authority.'),
('Leviticus', 8, 'adults', 7, 'How does the tabernacle anointing (verses 10-11) connect to the anointing of Aaron and his sons?', 'The tabernacle, its vessels, and the altar were anointed before Aaron — establishing that the place of service is consecrated before the servant, teaching that God''s house takes priority and the priest derives his authority from the sacred space he serves', 'Aaron was anointed first and then the tabernacle', 'The tabernacle anointing was a separate unrelated ceremony', 'Only the altar and Aaron needed anointing', 'a', 'Leviticus 8:10-12 — Moses anointed the tabernacle and all its vessels first (vv.10-11), sanctifying them, then anointed Aaron (v.12). The order teaches that the priest''s authority flows from the holiness of God''s appointed place of meeting, not the reverse.'),
('Leviticus', 8, 'adults', 8, 'What does the phrase "as the LORD commanded Moses" (repeated in vv.4,9,13,17,21,29,36) teach about the nature of acceptable worship?', 'The sevenfold repetition emphasises that priestly worship was valid only because it was precisely obedient to divine command — not invented, not improvised, not modified by human creativity; this principle of commanded worship is the foundation of Levitical religion and a continuing biblical principle', 'The phrase was only a scribal notation', 'The repetition suggests Moses made many mistakes', 'The phrase indicated the worship was flexible', 'a', 'Leviticus 8:36 — "So Aaron and his sons did all things which the LORD commanded by the hand of Moses." The sevenfold formula mirrors the creation week''s "and God saw that it was good" — worship that perfectly conforms to divine command receives divine approval. The contrast with Nadab and Abihu (ch.10) makes this principle tragically concrete.');

-- ═══ Leviticus Chapter 9 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 9, 'kids', 1, 'What amazing thing happened after Aaron offered the offerings on the eighth day?', 'Fire came out from the LORD and consumed the burnt offering on the altar', 'Rain fell from the sky', 'A rainbow appeared over the tabernacle', 'A dove flew down from heaven', 'a', 'Leviticus 9:24 — "And there came a fire out from before the LORD, and consumed upon the altar the burnt offering and the fat: which when all the people saw, they shouted, and fell on their faces."'),
('Leviticus', 9, 'kids', 2, 'What did all the people do when they saw the fire from the LORD?', 'They shouted and fell on their faces', 'They ran away in fear', 'They clapped and danced', 'They went back to their tents', 'a', 'Leviticus 9:24 — "Which when all the people saw, they shouted, and fell on their faces."'),
('Leviticus', 9, 'kids', 3, 'What appeared to all the people after Aaron blessed them?', 'The glory of the LORD', 'An angel with a sword', 'A bright star in the sky', 'A pillar of cloud and fire', 'a', 'Leviticus 9:23 — "And Moses and Aaron went into the tabernacle of the congregation, and came out, and blessed the people: and the glory of the LORD appeared unto all the people."'),
-- Teens
('Leviticus', 9, 'teens', 1, 'Why is the eighth day significant for the beginning of Aaron''s priestly ministry?', 'After the seven-day ordination period of consecration, the eighth day inaugurated the new, ongoing public ministry — seven represented completion of preparation, eight represented new beginning and the commencement of regular priestly service', 'Eight was simply the next calendar day', 'The seventh day was a rest day so offerings began on the eighth', 'The eighth day had no special meaning beyond logistics', 'a', 'Leviticus 9:1 — "And it came to pass on the eighth day, that Moses called Aaron and his sons, and the elders of Israel." The eighth day principle (circumcision on day 8, dedication of firstborns on day 8) consistently represents new beginning and inauguration into covenant life.'),
('Leviticus', 9, 'teens', 2, 'What offerings did Aaron bring for himself and for the people on the eighth day?', 'For himself: a calf for sin offering and a ram for burnt offering; for the people: a goat for sin offering, a calf and lamb for burnt offering, a bullock and ram for peace offerings, and a grain offering mingled with oil', 'Only two sheep for himself and the people combined', 'A single bullock for the entire congregation', 'Only grain and peace offerings without sin offerings', 'a', 'Leviticus 9:2-4 — The full complement of offerings required on the inaugural day demonstrates that Aaron''s priestly ministry immediately addressed the full range of Israel''s covenant needs: atonement (sin), consecration (burnt), consecration of work (grain), and fellowship (peace).'),
('Leviticus', 9, 'teens', 3, 'Why did Aaron need to offer a sin offering for himself before offering for the people?', 'Aaron was not sinless and needed his own atonement before he could effectively serve as mediator for others — the priest must be personally reconciled to God before interceding for the congregation', 'Aaron had committed a specific recent sin', 'The people required the priest to be humbled before them', 'The sin offering for Aaron was only a tradition, not required', 'a', 'Leviticus 9:7-8 — "Moses said unto Aaron, Go unto the altar, and offer thy sin offering, and thy burnt offering, and make an atonement for thyself, and for the people." Hebrews 7:27 contrasts this with Christ — "Who needeth not daily... to offer up sacrifice, first for his own sins."'),
('Leviticus', 9, 'teens', 4, 'What physical gesture did Aaron make toward the people when he blessed them?', 'He lifted up his hand toward the people and blessed them', 'He knelt before the congregation', 'He raised both arms above his head in a circle', 'He touched each person''s head individually', 'a', 'Leviticus 9:22 — "And Aaron lifted up his hand toward the people, and blessed them, and came down from offering of the sin offering, and the burnt offering, and peace offerings."'),
('Leviticus', 9, 'teens', 5, 'What was Moses and Aaron''s role together at the end of the inauguration service?', 'They went into the tabernacle of the congregation together, then came out and blessed the people — after which the glory of the LORD appeared', 'Moses performed all the final rites alone', 'Aaron entered alone while Moses waited outside', 'They sent the elders to bless the people in their place', 'a', 'Leviticus 9:23 — "And Moses and Aaron went into the tabernacle of the congregation, and came out, and blessed the people: and the glory of the LORD appeared unto all the people." The joint entry and emergence of the two leaders sealed the inaugurated priestly ministry.'),
-- Adults
('Leviticus', 9, 'adults', 1, 'What is the theological significance of the divine fire consuming Aaron''s first official offering rather than any human-kindled fire?', 'The altar fire''s origination from God Himself (9:24) rather than human effort established that true worship is received by divine initiative, not generated by human performance — worship is God''s gracious reception of what He Himself has prescribed and enabled', 'The divine fire was a one-time miracle with no ongoing meaning', 'Human fire was inferior for practical reasons only', 'The divine fire was immediately extinguished and replaced by human fire', 'a', 'Leviticus 9:24; 6:12-13 — "There came a fire out from before the LORD." This fire was then to be maintained perpetually (6:13). 1 Chronicles 21:26 and 2 Chronicles 7:1 record the same divine fire initiating Solomon''s temple worship — confirming it as the pattern of divinely-accepted worship throughout Israel''s history.'),
('Leviticus', 9, 'adults', 2, 'How does the phrase "the LORD will appear unto you" (9:6) function as a covenantal promise connecting to Exodus 29:43-46?', 'It fulfils the explicit promise of Exodus 29:43-46 where God said He would meet and sanctify the tabernacle by His glory — the appearance of the glory in 9:23-24 is the direct fulfilment of the Sinai covenant''s central promise that God would dwell among His people', 'The phrase was only a general encouragement', 'Exodus 29 and Leviticus 9 address completely different events', 'The glory only appeared to Moses privately', 'a', 'Leviticus 9:6; Exodus 29:43-46 — "I will meet with the children of Israel, and the tabernacle shall be sanctified by my glory... And I will dwell among the children of Israel." Leviticus 9:23-24 is the literal fulfilment of this tabernacle covenant, establishing the pattern for God''s glory inhabiting His house.'),
('Leviticus', 9, 'adults', 3, 'What typological significance does Aaron''s first offering for himself then for the people have for understanding Hebrews 7:26-27?', 'Hebrews 7:27 explicitly contrasts Aaron''s double offering (first for self, then for people) with Christ, who needed no sin offering for Himself — making the contrast a direct theological argument for Christ''s sinlessness and the superiority of His once-for-all priesthood', 'Hebrews 7 does not reference Leviticus 9''s pattern', 'Aaron''s self-offering was only an incidental detail', 'The comparison diminishes rather than exalts Christ''s priesthood', 'a', 'Leviticus 9:7-8; Hebrews 7:27 — "Who needeth not daily, as those high priests, to offer up sacrifice, first for his own sins, and then for the people''s: for this he did once, when he offered up himself." The pattern of Leviticus 9 is the precise foil against which the New Testament argues for Christ''s superior, permanent priesthood.'),
('Leviticus', 9, 'adults', 4, 'What is the relationship between Aaron''s blessing of the people (v.22) and the Aaronic/Priestly blessing of Numbers 6:24-26?', 'Leviticus 9:22 records the first formal priestly blessing of the congregation — Numbers 6:24-26 formalises the exact words: "The LORD bless thee and keep thee... make his face shine upon thee." The raised hand and the blessing formula together constitute the covenantal benediction', 'The two passages have no connection', 'Aaron''s blessing in chapter 9 was different from the Numbers formula', 'The Aaronic blessing was not yet established by chapter 9', 'a', 'Leviticus 9:22 — "Aaron lifted up his hand toward the people, and blessed them." Numbers 6:24-26 — "The LORD bless thee and keep thee: The LORD make his face shine upon thee... and give thee peace." 2 Corinthians 13:14 reflects the same triadic priestly blessing structure in the Apostolic benediction.'),
('Leviticus', 9, 'adults', 5, 'How does the congregation''s response of shouting and falling on their faces (9:24) model authentic human response to divine presence?', 'The shouting (rinnah — joyful acclaim) combined with prostration (falling on faces — the posture of utter awe and submission) demonstrates that authentic encounter with the glory of God produces simultaneous joy and holy fear — these are not opposites but the twin responses of creatures before their Creator', 'The people''s response was purely cultural convention', 'Falling on one''s face indicated displeasure or terror only', 'The shouting and falling were two separate events', 'a', 'Leviticus 9:24 — The verb vayaronu (they shouted/cried out) and vayippelu (they fell) together. Isaiah 6:1-5 records the same dual response — the seraphim''s praise and Isaiah''s prostration. Revelation 1:17 — John "fell at his feet as dead" at the vision of Christ in glory.'),
('Leviticus', 9, 'adults', 6, 'What is the chiastic structure of Leviticus 9 and how does it illuminate the chapter''s theology?', 'The chapter moves from preparation (elders summoned, offerings prescribed) → Aaron''s own atonement → Aaron''s offerings for the people → Moses and Aaron entering the tent → the glory appearing → divine fire consuming the offering — centering on the appearance of divine glory as the chapter''s theological apex', 'The chapter has no identifiable literary structure', 'The chapter is structured only as a sequential narrative', 'The theological climax is Aaron''s blessing, not the divine fire', 'a', 'Leviticus 9:1-7 (preparation and Aaron''s atonement), 9:8-21 (offerings for the people), 9:22-23 (blessing and entry into tent), 9:23-24 (glory + fire). The entire orchestration of sacrifices leads to the single climactic moment: God''s glory dwelling with His redeemed people — the purpose of the whole tabernacle system.'),
('Leviticus', 9, 'adults', 7, 'How does Leviticus 9 function as the liturgical inauguration of the Mosaic covenant''s worship system, analogous to other biblical inaugurations?', 'Just as the rainbow sealed Noah''s covenant (Genesis 9), and Sinai fire sealed the Mosaic law (Exodus 19), and Pentecostal fire sealed the New Covenant (Acts 2:3-4), so the fire from the LORD in Leviticus 9:24 inaugurates the priestly covenant — each covenant inaugurated by divine fire', 'Fire is only mentioned once as a unique miracle in the Bible', 'The inauguration in Leviticus 9 was not a covenantal sealing', 'The Day of Atonement, not Leviticus 9, inaugurated the priesthood', 'a', 'Leviticus 9:24; Genesis 15:17 (smoking furnace sealing Abrahamic covenant), Exodus 19:18 (Sinai fire for Mosaic law), 2 Chronicles 7:1 (fire for Solomonic temple), Acts 2:3 (tongues of fire for New Covenant). Divine fire is consistently the divine signature on covenant inaugurations.'),
('Leviticus', 9, 'adults', 8, 'What does the repetition of "as the LORD commanded" throughout chapters 8-9 and its contrast with Nadab and Abihu in chapter 10 reveal about the theology of Leviticus?', 'Precise obedience to God''s prescribed worship is the condition for divine acceptance and His glorious presence; any departure from His command — however well-intentioned — is "strange fire" that cannot receive divine approval and brings judgment instead of blessing', 'The commands were negotiable guidelines', 'Obedience and worship style were interchangeable in Leviticus', 'The contrast with chapter 10 is unrelated to the command-obedience theme', 'a', 'Leviticus 8:4,9,13,17,21,29; 9:5-6,7,10 — the commanded-obedience pattern builds to 9:24''s divine approval. Then 10:1 — "strange fire, which he commanded them not" — breaks the pattern with fatal consequences. The literary contrast is intentional: obedience → glory; disobedience → death. Isaiah 1:12 — "Who hath required this at your hand?"');

-- ═══ Leviticus Chapter 10 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 10, 'kids', 1, 'What did Nadab and Abihu, the sons of Aaron, do wrong?', 'They offered strange fire before the LORD, which He had not commanded them', 'They ate the sacred bread without permission', 'They left the tabernacle without being dismissed', 'They wore the wrong clothes to worship', 'a', 'Leviticus 10:1 — "And Nadab and Abihu, the sons of Aaron, took either of them his censer, and put fire therein, and put incense thereon, and offered strange fire before the LORD, which he commanded them not."'),
('Leviticus', 10, 'kids', 2, 'What happened to Nadab and Abihu when they offered strange fire?', 'Fire came out from the LORD and devoured them, and they died before the LORD', 'They were sent outside the camp', 'They were told to repeat the offering correctly', 'They were fined and put in prison', 'a', 'Leviticus 10:2 — "And there went out fire from the LORD, and devoured them, and they died before the LORD."'),
('Leviticus', 10, 'kids', 3, 'What did God command the priests not to drink before going into the tabernacle?', 'Wine or strong drink', 'Water from the river', 'Milk or honey', 'Any kind of broth', 'a', 'Leviticus 10:9 — "Do not drink wine nor strong drink, thou, nor thy sons with thee, when ye go into the tabernacle of the congregation, lest ye die: it shall be a statute for ever throughout your generations."'),
-- Teens
('Leviticus', 10, 'teens', 1, 'What was Moses'' explanation to Aaron about what happened to Nadab and Abihu?', '"This is it that the LORD spake, saying, I will be sanctified in them that come nigh me, and before all the people I will be glorified"', '"They had sinned too many times and this was their final punishment"', '"God was angry because they had not finished their ordination"', '"They brought the wrong type of incense from Egypt"', 'a', 'Leviticus 10:3 — "Then Moses said unto Aaron, This is it that the LORD spake, saying, I will be sanctified in them that come nigh me, and before all the people I will be glorified. And Aaron held his peace."'),
('Leviticus', 10, 'teens', 2, 'Who carried the bodies of Nadab and Abihu out of the camp, and what were Aaron and his remaining sons forbidden to do?', 'Mishael and Elzaphan (Aaron''s cousins) carried them out; Aaron, Eleazar, and Ithamar were forbidden to uncover their heads or rend their clothes, lest they die — the whole congregation would mourn instead', 'The Levites carried them; Aaron could mourn openly', 'Moses alone carried them out', 'Only Aaron was forbidden from mourning while his sons could weep', 'a', 'Leviticus 10:4-6 — "And Moses called Mishael and Elzaphan... and they came near, and carried them in their coats out of the camp... And Moses said unto Aaron, and unto Eleazar and unto Ithamar, his sons, Uncover not your heads, neither rend your clothes; lest ye die."'),
('Leviticus', 10, 'teens', 3, 'What three purposes does God give for the wine prohibition for priests in verse 10-11?', 'That the priests may put a difference between holy and unholy, between unclean and clean; and that they may teach the children of Israel all the statutes which the LORD hath spoken', 'To preserve the holiness of the wine for the people''s festivals', 'To prevent priests from becoming wealthy through trade', 'To ensure the priests were physically fit for carrying the ark', 'a', 'Leviticus 10:10-11 — "And that ye may put difference between holy and unholy, and between unclean and clean; And that ye may teach the children of Israel all the statutes which the LORD hath spoken unto them by the hand of Moses."'),
('Leviticus', 10, 'teens', 4, 'What mistake did Eleazar and Ithamar make with the sin offering goat, and how did Moses respond?', 'They burned the goat completely instead of eating it in the holy place; Moses was angry, but Aaron explained they had just experienced bereavement — and Moses accepted the explanation', 'They ate the offering in the wrong location', 'They forgot to burn any part of the offering', 'They gave the goat to the congregation instead of the priests', 'a', 'Leviticus 10:16-20 — Moses saw the goat burned and was angry. Aaron explained that given what had happened to his sons that day, eating the sin offering before the LORD would not have been proper. "And when Moses heard that, he was content."'),
('Leviticus', 10, 'teens', 5, 'What instruction did Moses give about where the priests were to eat their portions of the offerings?', 'The heave offering and wave offering were to be eaten in a clean place — by Aaron, his sons, and their daughters — as their portions from the offerings of the children of Israel', 'They could eat anywhere in the camp', 'The portions could only be eaten inside the tabernacle itself', 'Only male priests could eat the portions, never daughters', 'a', 'Leviticus 10:14 — "And the wave breast and heave shoulder shall ye eat in a clean place; thou, and thy sons, and thy daughters with thee: for they be thy due, and thy sons'' due, which are given out of the sacrifices of peace offerings of the children of Israel."'),
-- Adults
('Leviticus', 10, 'adults', 1, 'What does the term "strange fire" (esh zarah) reveal about the nature of Nadab and Abihu''s sin?', 'Zarah means "unauthorized, alien, or strange" — they used fire not prescribed by God, substituting their own initiative for divine command; the sin was not moral depravity but the arrogant assumption that God would accept any sincere offering, violating the principle of commanded worship', 'Their fire was literally taken from a foreign nation', 'Strange fire referred to an incorrect type of incense only', 'The term only means they used the wrong altar', 'a', 'Leviticus 10:1 — "Strange fire (esh zarah) which he commanded them not." Exodus 30:9 — "Ye shall offer no strange incense thereon." The same root zarah describes the foreign woman (Proverbs 2:16) and alien worship (Deuteronomy 32:16). The defining characteristic is not-commanded — worship that originates from human initiative rather than divine prescription.'),
('Leviticus', 10, 'adults', 2, 'What theological principle does Moses articulate in verse 3 about God''s holiness and its implications for those who minister near Him?', '"I will be sanctified in them that come nigh me, and before all the people I will be glorified" — those who draw nearest to God bear the greatest responsibility to honour His holiness, for God''s holiness must be displayed through those who represent Him', 'Moses was suggesting God was unfair in His judgment', 'The principle only applied to Aaron''s family', 'Holiness was secondary to sincerity of intent', 'a', 'Leviticus 10:3 — The two verbs are niphal reflexives — God will sanctify Himself through His ministers and glorify Himself before His people. Luke 12:48 — "Unto whomsoever much is given, of him shall be much required." 1 Peter 4:17 — "Judgment must begin at the house of God."'),
('Leviticus', 10, 'adults', 3, 'How does Aaron''s silence ("And Aaron held his peace") in verse 3 function as a theological statement?', 'Aaron''s silence is not passive indifference but reverent submission — he does not argue with God''s judgment, does not accuse God of injustice, does not seek revenge on Moses; it mirrors Job 40:4-5 and is presented as the appropriate response of human humility before sovereign divine holiness', 'Aaron was in shock and unable to speak', 'His silence indicated he secretly agreed with his sons', 'The silence was culturally expected but spiritually insignificant', 'a', 'Leviticus 10:3 — "And Aaron held his peace." The Hebrew vayiddom (וַיִּדֹּם) is from damam meaning "to be still, silent, in awe." Psalm 46:10 — "Be still, and know that I am God." Aaron''s response is the paradigm of theocentric grief that submits to divine judgment without protest.'),
('Leviticus', 10, 'adults', 4, 'What is the likely connection between the wine prohibition (vv.9-11) and Nadab and Abihu''s sin, and what does this teach?', 'The wine prohibition''s placement immediately after the incident strongly suggests Nadab and Abihu may have been intoxicated, impairing their judgment and leading to the unauthorised offering; the law then guards against the same cause in future priests', 'The wine prohibition was unrelated to the Nadab and Abihu incident', 'The prohibition applied only at night services', 'Wine was forbidden to all Israelites, not just priests', 'a', 'Leviticus 10:9 — "Do not drink wine nor strong drink... when ye go into the tabernacle of the congregation, lest ye die." The law''s placement immediately following vv.1-2 and its "lest ye die" warning (mirroring v.2) is the text''s implicit interpretive link. Many church fathers (Origen, Jerome) and Jewish commentators identified intoxication as the cause.'),
('Leviticus', 10, 'adults', 5, 'How does the New Testament use the Nadab and Abihu incident as a warning for the church?', 'Hebrews 12:28-29 warns believers to "serve God acceptably with reverence and godly fear: For our God is a consuming fire" — directly echoing the fire that consumed Nadab and Abihu and applying its lesson to New Covenant worshippers', 'The New Testament never references this incident', 'The incident is only used to contrast with the gentleness of the New Covenant', 'Only 1 Corinthians references the Leviticus 10 event', 'a', 'Hebrews 12:28-29 — "Serve God acceptably with reverence and godly fear: For our God is a consuming fire." 1 Corinthians 11:29-30 applies the same principle to the Lord''s Supper: eating and drinking unworthily brings judgment — "many are weak and sickly among you, and many sleep."'),
('Leviticus', 10, 'adults', 6, 'What does Aaron''s defence of Eleazar and Ithamar''s deviation (eating the sin offering vs. burning it) reveal about the flexibility and limits of priestly judgment?', 'Aaron demonstrates that in extraordinary circumstances of grief and defilement, the spirit of the law may supersede the letter — Moses accepted this, showing that priestly judgment (discernment between holy/common) was a genuine responsibility, not merely mechanical rule-following', 'Aaron was making excuses to avoid punishment', 'Priestly judgment had no legitimate role in the legal system', 'Moses rejected Aaron''s explanation and imposed a penalty', 'a', 'Leviticus 10:16-20 — Moses'' anger at the burned sin offering was reasonable by the letter of the law (6:26). But Aaron''s explanation — that eating the congregation''s sin offering while in personal mourning would have been inappropriate given his state — was accepted. Moses'' acceptance ("he was content") endorses the principle that priestly wisdom must sometimes navigate competing demands of law and circumstance.'),
('Leviticus', 10, 'adults', 7, 'How does the three-part teaching commission of verse 11 ("teach the children of Israel all the statutes") define the priest''s role beyond sacrifice?', 'The priest was not merely a ritual technician but a teacher (moreh) of Torah — his primary calling included instructing the people in God''s distinctions between holy/unholy, clean/unclean; this teaching dimension of priesthood is taken up in Malachi 2:7 and applied to Christ in Matthew 7:28-29', 'Priests were only sacrificial officials with no teaching role', 'Teaching was the exclusive domain of the prophets', 'Verse 11 was added later and is not part of the original priestly law', 'a', 'Leviticus 10:11; Malachi 2:7 — "For the priest''s lips should keep knowledge, and they should seek the law at his mouth: for he is the messenger of the LORD of hosts." Deuteronomy 17:18-19 assigned kings to read Torah daily. Priestly, prophetic, and royal offices all converge in Christ as Prophet, Priest, and King.'),
('Leviticus', 10, 'adults', 8, 'What is the literary and theological function of Leviticus 10 within the broader structure of Leviticus 8-10?', 'Chapters 8-10 form a tripartite narrative unit — ordination (ch.8), inaugural glory (ch.9), and catastrophic violation (ch.10) — establishing the sacred/profane distinction as the foundational principle of all Levitical religion, with ch.10 functioning as the cautionary climax that validates the severity of all subsequent purity legislation', 'Chapter 10 is an independent appendix unrelated to chapters 8-9', 'The literary unit begins at chapter 11 and chapter 10 is a conclusion to the law section', 'Chapters 8-10 have no structural unity', 'a', 'Leviticus 8-10 form the narrative centre of the first half of Leviticus. The sevenfold "as the LORD commanded" of ch.8-9 sets up the tragedy of ch.10''s "which he commanded them not." The fire of divine acceptance (9:24) becomes the fire of divine judgment (10:2) when the principle of commanded worship is violated — making ch.10 the interpretive key to all of Leviticus.');
